const orders = $input.all();

const statusLabels = {
  'new': 'Nowe',
  'processing': 'W realizacji',
  'shipped': 'Wysłane',
  'delivered': 'Dostarczone',
  'returned': 'Zwrócone'
};

const formattedOrders = orders.map(o => {
  let items = o.json.items;
  if (typeof items === 'string') {
    try {
      items = JSON.parse(items);
    } catch (e) {
      items = [];
    }
  }

  let shippingAddress = o.json.shipping_address;
  if (typeof shippingAddress === 'string') {
    try {
      shippingAddress = JSON.parse(shippingAddress);
    } catch (e) {
      shippingAddress = null;
    }
  }

  return {
    id: o.json.id,
    order_number: o.json.order_number,
    customer_name: o.json.customer_name,
    email: o.json.email,
    status: o.json.status,
    status_label: statusLabels[o.json.status] || o.json.status,
    items: items,
    items_count: items ? items.length : 0,
    total: parseFloat(o.json.total),
    shipping_method: o.json.shipping_method,
    tracking_number: o.json.tracking_number,
    carrier: o.json.carrier,
    shipping_address: shippingAddress,
    created_at: o.json.created_at,
    updated_at: o.json.updated_at
  };
});

return [{
  json: {
    orders: formattedOrders,
    total: formattedOrders.length
  }
}];
